    size_t di; (di < ZOPFLI_NUM_D) ==> stats->dists[di] == 0 })
{
    size_t i;
    for (i = 0; i < ZOPFLI_NUM_LL; i++)
        stats->litlens[i] = 0;
    for (i = 0; i < ZOPFLI_NUM_D; i++)
        stats->dists[i] = 0;
}

